SELECT * FROM tb_customer_service_message
WHERE session_id = #{sessionId, jdbcType=NVARCHAR}
ORDER BY create_time ASC

SELECT * FROM tb_customer_service_message
WHERE sender_id = #{userId, jdbcType=BIGINT} 
   OR receiver_id = #{userId, jdbcType=BIGINT}
ORDER BY create_time DESC

